116	.cancel-btn{padding:10px 20px;border:1px solid var(--border);border-radius:var(--radius);background:transparent;color:var(--text-dim);font-size:.85rem;font-family:var(--font);cursor:pointer;transition:all .2s}
117	.cancel-btn:hover{color:var(--danger);border-color:var(--danger);background:rgba(255,118,117,.08)}
118	.resume-btn{padding:12px 32px;border:none;border-radius:var(--radius);background:var(--success);color:#000;font-size:.95rem;font-weight:700;font-family:var(--font);cursor:pointer;transition:all .25s;white-space:nowrap;letter-spacing:.3px}
119	.resume-btn:hover{background:#00e6d9;box-shadow:0 0 30px rgba(0,206,201,.4);transform:translateY(-1px)}
120	.resume-btn:active{transform:scale(.97)}
121	.resume-btn.glow{animation:resGlow 2s ease-in-out infinite}
122	@keyframes resGlow{0%,100%{box-shadow:0 0 0 0 rgba(0,206,201,.5)}50%{box-shadow:0 0 16px 4px rgba(0,206,201,.35)}}
123	
124	.session-card{padding:14px 20px;border-top:1px solid var(--border);display:flex;flex-direction:column;gap:6px}
125	.session-row{display:flex;align-items:baseline;gap:12px}
126	.session-label{font-size:.75rem;color:var(--text-dim);text-transform:uppercase;letter-spacing:.5px;min-width:70px;flex-shrink:0}
127	.session-value{font-size:.85rem;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
128	.session-meta{display:flex;gap:24px;margin-top:4px}
129	.session-meta .session-label{min-width:auto;margin-right:6px}
130	.url-truncate{max-width:320px;display:inline-block}
131	
132	@media(max-width:640px){.action-bar{flex-direction:column;align-items:stretch}.resume-group{flex-direction:column}.cancel-btn,.resume-btn{width:100%;text-align:center}.session-meta{flex-direction:column;gap:4px}.pause-banner{flex-wrap:wrap}.pause-reason{margin-left:0;width:100%;margin-top:4px}.screenshot-viewport{max-height:35vh}}
133	</style>
134	</head>
135	<body>
136	<div class="container">
137	  <div class="header">
138	    <h1>Agent Nervous System</h1>
139	    <p>Purpose-built browser for AI agents — submit goals, watch live, see results</p>
140	  </div>
141	
142	  <div class="glass status-strip">
143	    <div>
144	      <span class="status-dot disconnected" id="wsDot"></span>
145	      <span id="wsStatus">Connecting...</span>
146	    </div>
147	    <div><span class="mode-badge thorough" id="modeBadge">Thorough</span></div>
148	    <div style="margin-left:auto;color:var(--text-dim)">Active: <strong id="activeCount">0</strong></div>
149	  </div>
150	
151	  <div class="glass goal-bar">
152	    <input type="text" id="goalInput" placeholder="What should the agent do? e.g., Search for flights from Delhi to Mumbai on June 5" autofocus>
153	    <button id="submitBtn" onclick="submitGoal()">▶ Run</button>
154	    <button onclick="toggleMode()" style="background:transparent;border:1px solid var(--border);font-size:.8rem;padding:14px 16px" title="Toggle fast/thorough mode">Fast</button>
155	  </div>
156	
157	  <!-- ── Live View Panel ─────────────────────────────── -->
158	  <div class="glass live-panel-section" id="liveView" style="display:none;padding:20px;margin-bottom:16px">
159	    <div style="display:flex;align-items:center;gap:16px;flex-wrap:wrap">
160	      <h2 style="font-size:1.1rem;font-weight:600;margin:0">📺 Live View</h2>
161	      <span style="font-size:.78rem;color:var(--text-dim)" id="liveStep">---</span>
162	      <span id="liveStatus" style="font-size:.78rem;padding:3px 10px;border-radius:20px;background:rgba(0,206,201,0.15);color:var(--success)">running</span>
163	    </div>
164	    <div style="display:flex;gap:16px;margin-top:16px;flex-wrap:wrap">
165	      <div style="flex:1;min-width:300px;background:#000;border-radius:8px;overflow:hidden;max-height:400px;display:flex;align-items:center;justify-content:center">
166	        <img id="liveViewScreenshot" src="" alt="Live agent view" style="width:100%;height:auto;display:block">
167	      </div>
168	      <div style="flex:1;min-width:250px;display:flex;flex-direction:column;gap:10px;font-size:.85rem">
169	        <div><span style="color:var(--text-dim)">Action:</span> <span id="liveAction" style="font-weight:600">---</span></div>
170	        <div><span style="color:var(--text-dim)">Sub-goal:</span> <span id="liveSubGoal">---</span></div>
171	        <div><span style="color:var(--text-dim)">Page:</span> <span id="livePage" style="word-break:break-all">---</span></div>
172	        <div><span style="color:var(--text-dim)">URL:</span> <span id="liveUrl" style="font-size:.78rem;color:var(--text-dim);word-break:break-all">---</span></div>
173	      </div>
174	    </div>
175	  </div>
176	
177	  <div class="glass eyes-panel">
178	    <h2>5 Eyes — Perception</h2>
179	    <div class="eyes-grid">
180	      <div class="glass eye-tile" id="eye-dom_reader"><div class="eye-icon">🔍</div><div class="eye-name">DOM Reader</div><div class="eye-status">idle</div></div>
181	      <div class="glass eye-tile" id="eye-vision"><div class="eye-icon">👁</div><div class="eye-name">Vision</div><div class="eye-status">idle</div></div>
182	      <div class="glass eye-tile" id="eye-page_diff"><div class="eye-icon">⚡</div><div class="eye-name">Page Diff</div><div class="eye-status">idle</div></div>
183	      <div class="glass eye-tile" id="eye-goal_verifier"><div class="eye-icon">✅</div><div class="eye-name">Goal Verifier</div><div class="eye-status">idle</div></div>
184	      <div class="glass eye-tile" id="eye-error_detector"><div class="eye-icon">🚨</div><div class="eye-name">Error Detector</div><div class="eye-status">idle</div></div>
185	    </div>
186	  </div>
187	
188	  <div class="goals-grid" id="goalsGrid">
189	    <div class="glass empty-state"><div class="empty-icon">🎯</div><p>No active goals. Submit a goal above to get started.</p></div>
190	  </div>
191	</div>
192	
193	<!-- ── Error Recovery Overlay ──────────────────────────── -->
194	<div id="liveOverlay" class="live-overlay hidden">
195	  <div class="live-panel glass">
196	    <div class="pause-banner" id="pauseBanner">
197	      <span class="pause-icon">⚠</span>
198	      <span class="pause-text" id="pauseText">AGENT PAUSED</span>
199	      <span class="pause-reason" id="pauseReason">CAPTCHA detected</span>
200	    </div>
201	    <div class="screenshot-viewport" id="screenshotViewport">
202	      <img id="liveScreenshot" src="" alt="Live browser view" class="screenshot-img" draggable="false">
203	      <div class="ripple-layer" id="rippleLayer"></div>
204	    </div>
205	    <div class="action-bar">
206	      <div class="input-group">
207	        <input type="text" id="textInput" class="text-input" placeholder="Type here then press Enter..." autocomplete="off">
208	        <button class="key-btn" id="keyTab">Tab</button>
209	        <button class="key-btn" id="keyEnter">Enter</button>
210	        <button class="key-btn" id="keyEscape">Esc</button>
211	        <button class="key-btn" id="keyBackspace">⌫</button>
212	      </div>
213	      <div class="resume-group">
214	        <button class="cancel-btn" id="cancelRecoveryBtn">Cancel Goal</button>
215	        <button class="resume-btn glow" id="resumeBtn">▶ Resume Agent</button>
216	      </div>
217	    </div>
218	    <div class="session-card" id="sessionCard">
219	      <div class="session-row"><span class="session-label">Goal</span><span class="session-value" id="sessGoal">---</span></div>
220	      <div class="session-row"><span class="session-label">Sub-goal</span><span class="session-value" id="sessSubGoal">---</span></div>
221	      <div class="session-row session-meta">
222	        <div><span class="session-label">Steps</span><span class="session-value" id="sessSteps">0</span></div>
223	        <div><span class="session-label">Paused</span><span class="session-value" id="sessPaused">---</span></div>
224	        <div><span class="session-label">URL</span><span class="session-value url-truncate" id="sessUrl">---</span></div>
225	      </div>
226	    </div>
227	  </div>
228	</div>
229	
230	<script>
231	const API = '';
232	let ws=null,goals={},wsConnected=false,fastMode=false;
233	
234	function connectWS(){
235	  ws=new WebSocket(`ws://${location.host}/ws`);
236	  ws.onopen=()=>{wsConnected=true;document.getElementById('wsDot').className='status-dot connected';document.getElementById('wsStatus').textContent='Connected'};
237	  ws.onclose=()=>{wsConnected=false;document.getElementById('wsDot').className='status-dot disconnected';document.getElementById('wsStatus').textContent='Disconnected - reconnecting...';setTimeout(connectWS,2000)};
238	  ws.onmessage=(e)=>{try{handleEvent(JSON.parse(e.data))}catch(ex){}};
239	}
240	function handleEvent(d){
241	  if(d.type==='goal_created'){goals[d.goal_id]=d;renderGoals()}
242	  else if(d.type==='goal_update'){
243	    if(goals[d.goal_id]){goals[d.goal_id].progress=d.progress;goals[d.goal_id].status=d.status;if(d.sub_goals)goals[d.goal_id].sub_goals=d.sub_goals}else{goals[d.goal_id]=d}
244	    renderGoals();
245	    if(d.eye_updates)for(let[k,v]of Object.entries(d.eye_updates)){let el=document.getElementById('eye-'+k.replace('_','-'));if(el){el.className='glass eye-tile '+(v==='active'?'active':v==='error'?'error':v==='warning'?'warning':'');el.querySelector('.eye-status').textContent=v}}
246	  }else if(d.type==='eye_report'){let el=document.getElementById('eye-'+d.eye_name);if(el){el.className='glass eye-tile active';el.querySelector('.eye-status').textContent='active (confidence: '+(d.confidence||0).toFixed(2)+')'}}
247	  // ── Error Recovery Events ──────────────────────────
248	  else if(d.type==='session_paused'){openRecoveryPanel(d)}
249	  else if(d.type==='live_screenshot'){updateLiveScreenshot(d)}
250	  else if(d.type==='agent_resumed'){closeRecoveryPanel();showToast('Agent resumed — continuing execution','success')}
251	  else if(d.type==='action_result'){if(!d.success){showToast('Action failed: '+(d.result||'unknown'),'error')}}
252	  // ── Live View Event ────────────────────────────────
253	  else if(d.type==='agent_step'){updateLiveView(d)}
254	}
255	const API_KEY='dev-secret-key-123';
256	async function submitGoal(){
257	  let goal=document.getElementById('goalInput').value.trim();if(!goal)return;
258	  let btn=document.getElementById('submitBtn');btn.disabled=true;btn.textContent='Running...';
259	  try{
260	    let r=await fetch(API+'/api/v1/goals',{method:'POST',headers:{'Content-Type':'application/json','X-API-Key':API_KEY},body:JSON.stringify({description:goal,max_steps:50,context:fastMode?'mode=fast':''})});
261	    if(r.ok){document.getElementById('goalInput').value='';showToast('Goal created','success')}else{let t=await r.text();showToast('Failed: '+t,'error')}
262	  }catch(e){showToast('Error: '+e.message,'error')}
263	  btn.disabled=false;btn.textContent='▶ Run';
264	}
265	function renderGoals(){
266	  let entries=Object.entries(goals).sort((a,b)=>b[1].created_at-a[1].created_at),grid=document.getElementById('goalsGrid');
267	  if(!entries.length){grid.innerHTML='<div class="glass empty-state"><div class="empty-icon">🎯</div><p>No active goals. Submit a goal above to get started.</p></div>';return}
268	  document.getElementById('activeCount').textContent=entries.filter(([,g])=>g.status==='active').length;
269	  grid.innerHTML=entries.map(([id,g])=>{
270	    let pct=Math.round((g.progress||0)*100),sc=g.status==='completed'?'completed':g.status==='failed'?'failed':'';
271	    let sg=g.sub_goals||[],shtml=sg.length?('<div class="sub-goals">'+sg.map(s=>{let dc=s.status==='Done'?'done':s.status==='Active'?'active':s.status==='Blocked'?'blocked':'pending';return`<div class="sub-goal-item"><span class="sub-goal-dot ${dc}"></span>${e(s.description)}</div>`}).join('')+'</div>'):'';
272	    return`<div class="glass goal-card ${sc}"><div class="goal-title">${e(g.description)}</div><div class="goal-meta"><span>${pct}%</span><span style="text-transform:capitalize">${g.status}</span></div><div class="progress-bar"><div class="progress-fill" style="width:${pct}%"></div></div>${shtml}</div>`
273	  }).join('')
274	}
275	function toggleMode(){fastMode=!fastMode;document.getElementById('modeBadge').textContent=fastMode?'Fast':'Thorough';document.getElementById('modeBadge').className='mode-badge '+(fastMode?'fast':'thorough');showToast(`Mode: ${fastMode?'Fast (skip Eyes)':'Thorough (full 5 Eyes)'}`,'success')}
276	function showToast(m,t){let el=document.createElement('div');el.className='toast '+t;el.textContent=m;document.body.appendChild(el);setTimeout(()=>el.remove(),4000)}
277	function e(s){let d=document.createElement('div');d.textContent=s;return d.innerHTML}
278	document.getElementById('goalInput').addEventListener('keydown',e=>{if(e.key==='Enter')submitGoal()});
279	
280	// ── Live View ───────────────────────────────────────────────
281	function updateLiveView(d){
282	  let lv=document.getElementById('liveView');
283	  lv.style.display='block';
284	  if(d.screenshot_base64){document.getElementById('liveViewScreenshot').src='data:image/png;base64,'+d.screenshot_base64}
285	  document.getElementById('liveAction').textContent=d.action||'---';
286	  document.getElementById('liveSubGoal').textContent=d.sub_goal||'---';
287	  document.getElementById('livePage').textContent=d.page_title||d.page_url||'---';
288	  document.getElementById('liveUrl').textContent=d.page_url||'---';
289	  document.getElementById('liveStep').textContent='Step '+d.step+' · '+d.page_type;
290	}
291	
292	// ── Error Recovery — State & DOM ───────────────────────────
293	let recovery={active:false,sessionId:null,goalId:null,pausedAt:null,timer:null,goalDesc:'',subGoal:'',stepCount:0,pageUrl:''};
294	let recoveryDom={};
295	function cacheRecoveryDom(){
296	  recoveryDom.overlay=document.getElementById('liveOverlay');
297	  recoveryDom.banner=document.getElementById('pauseBanner');
298	  recoveryDom.pauseText=document.getElementById('pauseText');
299	  recoveryDom.pauseReason=document.getElementById('pauseReason');
300	  recoveryDom.viewport=document.getElementById('screenshotViewport');
301	  recoveryDom.screenshot=document.getElementById('liveScreenshot');
302	  recoveryDom.rippleLayer=document.getElementById('rippleLayer');
303	  recoveryDom.textInput=document.getElementById('textInput');
304	  recoveryDom.resumeBtn=document.getElementById('resumeBtn');
305	  recoveryDom.cancelBtn=document.getElementById('cancelRecoveryBtn');
306	  recoveryDom.sessGoal=document.getElementById('sessGoal');
307	  recoveryDom.sessSubGoal=document.getElementById('sessSubGoal');
308	  recoveryDom.sessSteps=document.getElementById('sessSteps');
309	  recoveryDom.sessPaused=document.getElementById('sessPaused');
310	  recoveryDom.sessUrl=document.getElementById('sessUrl');
311	}
312	let recoveryWired=false;
313	function wireRecovery(){
314	  if(recoveryWired)return;
315	  cacheRecoveryDom();
316	  let vp=recoveryDom.viewport;
317	  // Click on screenshot → page coordinates
318	  vp.addEventListener('pointerdown',()=>{vp.dataset.pressed='1'});
319	  vp.addEventListener('pointerup',(e)=>{
320	    vp.dataset.pressed='0';
321	    let img=recoveryDom.screenshot,imgRect=img.getBoundingClientRect();
322	    let x=e.clientX-imgRect.left,y=e.clientY-imgRect.top;
323	    let sx=img.naturalWidth/imgRect.width,sy=img.naturalHeight/imgRect.height;
324	    let px=Math.round(x*sx),py=Math.round(y*sy);
325	    // Ripple
326	    let r=document.createElement('div');r.className='click-ripple';
327	    r.style.left=(e.clientX-vp.getBoundingClientRect().left)+'px';
328	    r.style.top=(e.clientY-vp.getBoundingClientRect().top)+'px';
329	    recoveryDom.rippleLayer.appendChild(r);
330	    r.addEventListener('animationend',()=>r.remove());
331	    sendCmd('human_click',{x:px,y:py});
332	  });
333	  vp.addEventListener('selectstart',e=>e.preventDefault());
334	  // Text input → Enter sends type + key
335	  recoveryDom.textInput.addEventListener('keydown',(e)=>{
336	    if(e.key==='Enter'){
337	      e.preventDefault();
338	      let t=recoveryDom.textInput.value.trim();
339	      if(t){sendCmd('human_type',{text:t});sendCmd('human_key',{key:'Enter'})}
340	      recoveryDom.textInput.value='';
341	    }else if(e.key==='Escape'){recoveryDom.textInput.value=''}
342	  });
343	  // Key buttons
344	  document.getElementById('keyTab').addEventListener('click',()=>sendCmd('human_key',{key:'Tab'}));
345	  document.getElementById('keyEnter').addEventListener('click',()=>{let t=recoveryDom.textInput.value.trim();recoveryDom.textInput.value='';if(t)sendCmd('human_type',{text:t});sendCmd('human_key',{key:'Enter'})});
346	  document.getElementById('keyEscape').addEventListener('click',()=>sendCmd('human_key',{key:'Escape'}));
347	  document.getElementById('keyBackspace').addEventListener('click',()=>sendCmd('human_key',{key:'Backspace'}));
348	  // Resume / Cancel
349	  recoveryDom.resumeBtn.addEventListener('click',()=>{sendCmd('resume_agent',{goal_id:recovery.goalId});closeRecoveryPanel()});
350	  recoveryDom.cancelBtn.addEventListener('click',()=>{if(confirm('Cancel this goal?')){sendCmd('cancel_goal',{goal_id:recovery.goalId});closeRecoveryPanel()}});
351	  // Keyboard: R=resume, Esc=cancel (only when input not focused)
352	  document.addEventListener('keydown',(e)=>{
353	    if(!recovery.active||document.activeElement===recoveryDom.textInput)return;
354	    if(e.key==='r'||e.key==='R'){e.preventDefault();recoveryDom.resumeBtn.click()}
355	    else if(e.key==='Escape'){e.preventDefault();recoveryDom.cancelBtn.click()}
356	  });
357	  recoveryWired=true;
358	}
359	function sendCmd(type,extra){
360	  if(!ws||!wsConnected||!recovery.sessionId)return;
361	  ws.send(JSON.stringify({type:type,session_id:recovery.sessionId,...extra}));
362	}
363	// ── Open / Close / Update ───────────────────────────────────
364	function openRecoveryPanel(d){
365	  wireRecovery();
366	  recovery.active=true;
367	  recovery.sessionId=d.session_id||'';
368	  recovery.goalId=d.goal_id||'';
369	  recovery.goalDesc=d.goal_description||'';
370	  recovery.subGoal=d.sub_goal||'';
371	  recovery.stepCount=d.step_count||0;
372	  recovery.pageUrl=d.page_url||'';
373	  recovery.pausedAt=new Date();
374	  recovery.pauseReason=d.block_reason||'unknown';
375	  // Banner
376	  recoveryDom.banner.className='pause-banner'+(d.block_reason==='login_wall'||d.block_reason==='paywall'?' warning':'');
377	  recoveryDom.pauseText.textContent='AGENT PAUSED';
378	  recoveryDom.pauseReason.textContent=d.block_reason||'Escalation';
379	  // Session card
380	  recoveryDom.sessGoal.textContent=recovery.goalDesc||'---';
381	  recoveryDom.sessSubGoal.textContent=recovery.subGoal||'---';
382	  recoveryDom.sessSteps.textContent=String(recovery.stepCount);
383	  recoveryDom.sessUrl.textContent=recovery.pageUrl||'---';
384	  // Screenshot
385	  if(d.screenshot_base64){recoveryDom.screenshot.src='data:image/png;base64,'+d.screenshot_base64}
386	  recoveryDom.rippleLayer.innerHTML='';
387	  recoveryDom.textInput.value='';
388	  recoveryDom.overlay.classList.remove('hidden');
389	  recoveryDom.resumeBtn.classList.add('glow');
390	  // Timer
391	  if(recovery.timer)clearInterval(recovery.timer);
392	  recovery.timer=setInterval(updatePauseTimer,1000);
393	  updatePauseTimer();
394	  setTimeout(()=>recoveryDom.textInput.focus(),100);
395	  showToast('Agent paused — '+recovery.pauseReason+'. Interact with the live page.','warning');
396	}
397	function closeRecoveryPanel(){
398	  recovery.active=false;
399	  if(recovery.timer){clearInterval(recovery.timer);recovery.timer=null}
400	  recoveryDom.overlay.classList.add('hidden');
401	  recoveryDom.screenshot.src='';
402	}
403	function updateLiveScreenshot(d){
404	  if(!recovery.active||d.session_id!==recovery.sessionId)return;
405	  if(recoveryDom.viewport.dataset.pressed==='1')return;
406	  if(d.data_base64){recoveryDom.screenshot.src='data:image/png;base64,'+d.data_base64}
407	}
408	function updatePauseTimer(){
409	  if(!recovery.pausedAt)return;
410	  let s=Math.floor((Date.now()-recovery.pausedAt)/1000);
411	  recoveryDom.sessPaused.textContent=Math.floor(s/60)+'m '+(s%60)+'s';
412	}
413	connectWS();
414	</script>
415	</body>
416	</html>
